# 1. Sampling efficiency and indices --------------------------------------

#Load packages
library(vegan)       
library(fossil)      
library(FD)          
library(ape)         
library(picante)     
library(phyloregion) 


# 1.1 Sampling efficiency -------------------------------------------------
#Load dataset
abund <- read.table("Species abundance.csv", sep=",", header=T)

#Keep only numeric species columns
sp <- abund[, sapply(abund, is.numeric)]
sp[is.na(sp)] <- 0

# Total pooled Chao1 
total_abund <- matrix(colSums(sp), nrow = 1) # 1 row = pooled community
chao_total <- chao1(total_abund, taxa.row = FALSE)
chao_total

#Rarefraction
sp_accum <- specaccum(sp, method = "random")
plot(sp_accum, 
     col = "blue",
     ci.type = "poly",
     ci.col = adjustcolor("blue", 0.2),
     xlab = "Sampling units (sites)",
     ylab = "Species richness",
     main = "Sample-based rarefaction")

# 1.2 Functional indices --------------------------------------------------
#Load the datasets
traits <- read.table("Trait_variables.csv", sep=",", header=T)
abund <- read.table("Species abundance.csv", sep=",", header=T)


# Set row names for datasets
rownames(abund) = abund[, 1]; abund <- abund[, -1]
rownames(traits) = traits$Species
traits = traits[, -which(names(traits) == "Species")]

# Check if row names match column names 
all(rownames(traits) %in% colnames(abund))
all(colnames(abund) %in% rownames(traits))
row_missing <- setdiff(rownames(traits), colnames(abund))
col_missing <- setdiff(colnames(abund), rownames(traits))

# Print the mismatches
row_missing
col_missing


traits <- as.matrix(traits)
abund <- as.matrix(abund)
sapply(traits, is.numeric)
sapply(abund, is.numeric)

#Calculate functional diversity indices
results <- dbFD(traits, abund)
print(results)

#Visualizing the indices 
barplot(results$FRic, main = "Functional Richness", ylab = "FRic")
barplot(results$FEve, main = "Functional Eveness", ylab = "FEve")
barplot(results$FDiv, main = "Functional Diversity", ylab = "FDiv")
barplot(results$FDis, main = "Functional Dispersion", ylab = "FDis")
barplot(results$RaoQ, main = "Rao’s Quadratic Entropy", ylab = "RaoQ")



# 1.3 Phylogenetic indices ------------------------------------------------

#Load the phylogenetic tree 
phylo_tree <- read.tree("EUROPEAN_BUTTERFLIES_FULLMCC_DROPTIPED.nwk")
print(phylo_tree)
print(phylo_tree$tip.label)
plot(phylo_tree)
str(phylo_tree)

#Create my own phyl. tree 
#Subset and load species list
species_list <- read.csv("Species_list.csv")

# Extract species names as a vector
species_names <- species_list$Species
print(species_names)

# Ensure all species in the list are in the phylogenetic tree
species_to_keep <- species_names[species_names %in% phylo_tree$tip.label]

# Subset the phylogenetic tree to keep only the species list
my_tree <- drop.tip(phylo_tree, setdiff(phylo_tree$tip.label, species_to_keep))

missing_species <- setdiff(species_names, phylo_tree$tip.label)
if (length(missing_species) > 0) {
  cat("Warning: These species are not in the phylogenetic tree:\n")
  print(missing_species)
}


#Plot
plot(my_tree)
title("My Phylogenetic Tree")
str(phylo_tree)

plot(my_tree, type = "fan", cex = 0.6) #### circular layout
title("Circular Phylogenetic Tree")


#Load community data 
comm= read.table("Species abundance.csv", sep=",", header=T)
str(comm)
print(comm)
rownames(comm) = comm[, 1]; comm <- comm[, -1]

#Direct replacement of the species 
colnames(comm)[colnames(comm) == "Satyrium_w.album"] <- "Satyrium_w-album"

My_Tree <- match.phylo.comm(phy = my_tree, 
                            comm = comm)$phy
CleanComm <- match.phylo.comm(phy = my_tree, 
                              comm = comm)$comm
#No species was excluded this time, the tree still includes all 80 species

str(My_Tree)
plot(My_Tree,
     cex = 0.4)


#Phylogenetic diversity
PD <- pd(samp = CleanComm, 
         tree = My_Tree,
         include.root = FALSE)
print(PD)

#PD - SR
cor.test(PD$PD, PD$SR)

#Visualize
plot(PD$PD, 
     PD$SR, 
     xlab = "Phylogenetic Diversity", ylab = "Species Richness", 
     pch = 16)

#Standardized effect sizes of PD 
ses.pd <- ses.pd(samp = CleanComm, 
                 tree = My_Tree, 
                 null.model = "taxa.labels", 
                 runs = 1000)
print(ses.pd)


# Create a matrix of cophenetic distances among taxa
cophenDist <- cophenetic.phylo(My_Tree)
print(cophenDist)

# Standardized Effect Size of the MPD
ses.mpd <- ses.mpd(CleanComm, 
                   cophenDist, 
                   null.model = "taxa.labels", 
                   abundance.weighted = FALSE, 
                   runs = 100)
head(ses.mpd)

# Calculate Net Relatedness Index
NRI <- as.matrix(-1 * 
                   ((ses.mpd[,2] - ses.mpd[,3]) /
                      ses.mpd[,4]))
rownames(NRI) <- row.names(ses.mpd)
colnames(NRI) <- "NRI"

print(NRI)


#Phylogenetic endemism 

CleanComm_mat <- as.matrix(CleanComm)
PE <- phylo_endemism(CleanComm_mat, My_Tree, weighted = TRUE)
print(PE)

# 2. Comparative analyses -------------------------------------------------

# 2.A Mountain -------------------------------------------------------------

#Load packages
library(vegan)        
library(fossil)        
library(indicspecies)  
library(ggplot2)       
library(dplyr)         
library(pairwiseAdonis) 


# 2.A.1 Rarefraction ------------------------------------------------
#Load dataset
mount <- read.table("matrix_mount.csv", sep=",", header=TRUE)

grp <- factor(mount$Group)   
sp  <- mount[, -(1:2)]      
sp_T <- sp[grp == "T", ]
sp_S <- sp[grp == "S", ]

# species rarefaction
accum_T <- specaccum(sp_T, method = "random")
accum_S <- specaccum(sp_S, method = "random")

plot(accum_T, col="blue", ci.type="poly", ci.col=adjustcolor("blue", 0.2))
plot(accum_S, add=TRUE, col="red", ci.type="poly", ci.col=adjustcolor("red", 0.2))
legend("bottomright", legend=c("F", "G"), col=c("blue", "red"), lty=1, bty="n")

# Chao1 
T_pool <- matrix(colSums(sp_T), nrow = 1)
S_pool <- matrix(colSums(sp_S), nrow = 1)

chao_T <- chao1(T_pool, taxa.row = FALSE)
chao_S <- chao1(S_pool, taxa.row = FALSE)

chao_T
chao_S


# 2.A.2 Mann–Whitney test ------------------------------------------------------------------
#Load dataset
df <- read.table("S_T.csv", sep=",", header=TRUE)
str(df)

num_vars <- names(df)[sapply(df, is.numeric)]
results <- sapply(num_vars, function(v) {
  test <- wilcox.test(df[[v]] ~ df$Group)
  c(W = test$statistic, p.value = test$p.value)
})

results_df <- as.data.frame(t(results))

#Add BH-adjusted p-values
results_df$p.value <- as.numeric(results_df$p.value)
results_df$p.BH <- p.adjust(results_df$p.value, method = "BH")

results_df <- results_df[order(results_df$p.value), ]
results_df


# 2.A.3 NMDS --------------------------------------------------------------
com = mount[,3:ncol(mount)]
dist_matrix <- vegdist(com, method = "bray")
set.seed(999)
nmds <- metaMDS(dist_matrix, k = 2, trymax = 100, autotransform = FALSE)
nmds

plot(nmds)
class(nmds)
print(scores(nmds))

#plot
ord <- as.data.frame(scores(nmds, display = "sites"))
ord$Group <- mount$Group

ggplot(ord, aes(x = NMDS1, y = NMDS2, color = Group, fill = Group, shape = Group)) +
  stat_ellipse(aes(group = Group), type = "norm", level = 0.68,
               geom = "polygon", alpha = 0.18, linewidth = 0.8) +
  stat_ellipse(aes(group = Group), type = "norm", level = 0.68,
               geom = "path", linewidth = 0.8) +
  geom_point(size = 3, alpha = 0.9) +
  theme_bw() +
  theme(panel.grid = element_blank(),
        legend.title = element_text(size = 11)) +
  labs(title = "NMDS — Community composition in forest clearings vs grasslands",
       x = "NMDS1", y = "NMDS2")



# 2.A.4 PERMANOVA ---------------------------------------------------------

pairwise.adonis2(dist_matrix ~ Group, data = mount, permutations = 999)

#Test for homogeneity of multivariate dispersions
bd <- betadisper(dist_matrix, mount$Group)
bd
anova(bd)         # tests if dispersions differ significantly between S and T
permutest(bd, permutations = 9999)  
plot(bd)

# 2.A.5 Indicator species -------------------------------------------------
#Load dataset
mount <- read.table("matrix_mount.csv", sep=",", header=TRUE)

set.seed(123)
indval <- multipatt(com, mount$Group, func = "IndVal.g", duleg = TRUE, control = how(nperm = 9999))
summary(indval)

#print A (specificity) and B (fidelity) 
summary(indval, indvalcomp = TRUE)



