# 2.C.3 Friedman test -----------------------------------------------------

#Load dataset
dat <- read.table("friedman.csv", sep=",", header=T)

#Tidy
dat <- dat %>%
  mutate(
    Group = factor(Group, levels = c("A","B","C"))
  ) %>%
  group_by(Sites) %>%                      
  filter(n_distinct(Group) == 3) %>%
  ungroup()

# Remove non-numeric columns
tmp <- dat[, !(names(dat) %in% c("Sites", "Group"))]

# Keep only numeric variables
num_vars <- names(tmp)[sapply(tmp, is.numeric)]

num_vars

long <- dat %>%
  pivot_longer(
    cols = all_of(num_vars),
    names_to = "Variable",
    values_to = "Value"
  ) %>%
  filter(!is.na(Value))

#Loop for Friedman tests per variable 
friedman_results <- long %>%
  group_by(Variable) %>%
  friedman_test(Value ~ Group | Sites) %>%
  ungroup()

#Kendall's W effect size per variable
friedman_effect <- long %>%
  group_by(Variable) %>%
  friedman_effsize(Value ~ Group | Sites) %>%
  ungroup()

#Paired post-hoc Wilcoxon tests (holm) per variable 
posthoc_results <- long %>%
  group_by(Variable) %>%
  pairwise_wilcox_test(
    Value ~ Group,
    paired = TRUE,
    p.adjust.method = "holm",
    id = "Sites"
  ) %>%
  ungroup()


#Pairwise Wilcoxon effect size r per variable

long_safe <- long %>%
  group_by(Variable) %>%
  filter(n_distinct(Value) > 1) %>%
  ungroup()

posthoc_effect <- long_safe %>%
  group_by(Variable) %>%
  wilcox_effsize(
    Value ~ Group,
    paired = TRUE,
    comparisons = list(c("A", "B"), c("A", "C"), c("B", "C"))
  ) %>%
  ungroup()

posthoc_results_with_r <- posthoc_results %>%
  left_join(
    posthoc_effect %>%
      select(Variable, group1, group2, effsize, magnitude),
    by = c("Variable", "group1", "group2")
  ) %>%
  rename(
    r = effsize,
    r_magnitude = magnitude
  )


#Summaries 
friedman_results
friedman_effect
posthoc_results_subset <- posthoc_results[, c("Variable", "group1", "group2", "p", "p.adj", "p.adj.signif")]
posthoc_results_subset

#Export 
write.csv(friedman_results, "friedman_results.csv", row.names = FALSE)
write.csv(friedman_effect,  "friedman_effectsize.csv", row.names = FALSE)
write.csv(posthoc_results,  "posthoc_results.csv", row.names = FALSE)
write.csv(posthoc_results_with_r, "posthoc_results_with_r.csv", row.names = FALSE)

#Compute the median per group
long %>%
  group_by(Variable, Group) %>%
  summarise(Median = median(Value, na.rm = TRUE)) %>%
  arrange(Variable, Group)

#Median + IQR for 
summ_median_iqr <- long %>%
  group_by(Variable, Group) %>%
  summarise(
    n    = sum(!is.na(Value)),
    q1   = quantile(Value, 0.25, na.rm = TRUE),
    median = median(Value, na.rm = TRUE),
    q3   = quantile(Value, 0.75, na.rm = TRUE),
    IQR  = IQR(Value, na.rm = TRUE),
    .groups = "drop"
  )

#binary variables: % of 1s per group
bin_flags <- long %>%
  group_by(Variable) %>%
  summarise(is_binary = all(na.omit(Value) %in% c(0,1)),
            .groups = "drop")

binary_vars <- bin_flags %>% filter(is_binary) %>% pull(Variable)

summ_binary_props <- long %>%
  filter(Variable %in% binary_vars) %>%
  group_by(Variable, Group) %>%
  summarise(
    n_sites   = n_distinct(Sites),
    count_1   = sum(Value == 1, na.rm = TRUE),
    prop_1    = mean(Value, na.rm = TRUE),          
    perc_1    = 100 * prop_1,                       
    .groups = "drop"
  )

#Export
write_csv(summ_median_iqr,  "summary_median_IQR_by_group.csv")
write_csv(summ_binary_props, "summary_binary_proportions_by_group.csv")


