# 3.1 data exploration ----------------------------------------------------

res_vars <- c("SR", "Abund", "Fric", "PD", "PE")

pre_vars  <- c("Elev", "Slope", "Aheight","Flower", "Veg", "Shrubs", "Soil", "Stones", "Litter" , "Sheight")

plot_list <- list()

for (x in res_vars) {
  for (y in pre_vars) {
    
    p <- ggplot(var, aes_string(x = x, y = y)) +
      geom_point(size = 1.7, alpha = 0.8) +
      geom_smooth(method = "lm", se = FALSE, color = "red", linewidth = 0.8) +
      labs(x = x, y = y, title = paste(y, "vs", x)) +
      theme_minimal(base_size = 10)
    
    plot_list[[paste(x, y, sep = "_")]] <- p
  }
}

# Combine into a grid 
