full_grid


rownames(var) = var[, 1]; var <- var[, -1]
numeric <- var[, sapply(var, is.numeric)]
str(numeric)


# 3.2 Spearman correlations -----------------------------------------------

spearman_matrix <- cor(numeric, method = "spearman", use = "pairwise.complete.obs")
pval_matrix <- matrix(NA, ncol(numeric), ncol(numeric))
rownames(pval_matrix) <- colnames(numeric)
colnames(pval_matrix) <- colnames(numeric)

# Loop through each pair of columns
for (i in 1:ncol(numeric)) {
  for (j in i:ncol(numeric)) {
    valid_rows <- complete.cases(numeric[, c(i, j)])
    test <- cor.test(numeric[valid_rows, i], numeric[valid_rows, j], method = "spearman", exact = FALSE)
    pval_matrix[i, j] <- test$p.value
    pval_matrix[j, i] <- test$p.value  
  }
}


corrplot(spearman_matrix, method = "color", type = "upper", tl.cex = 0.6)

# Set significance level 
alpha <- 0.05
significant_correlations <- pval_matrix < alpha

# Extract the specific pairs that are significant:
significant_pairs <- which(significant_correlations, arr.ind = TRUE)

# View the significant pairs along with their correlation coefficients and p-values
significant_info <- data.frame(
  Var1 = colnames(spearman_matrix)[significant_pairs[, 1]],
  Var2 = colnames(spearman_matrix)[significant_pairs[, 2]],
  Correlation = spearman_matrix[significant_pairs],
  P_value = pval_matrix[significant_pairs]
)

print(significant_info)

