# 3.6.1 Species richness --------------------------------------------------

set.seed(1233) # For reproducibility

X1 <- model.matrix(SR ~ Elev + Slope + Aheight + Flower, data = var) [,-1]
Y1 <- var[, "SR"]

# Penalty type (alpha=1 is lasso, alpha=0.5 is elastic regression, alpha=0 is the ridge)
cv.lambda.lasso1 <- cv.glmnet(x=X1, y=Y1, 
                              alpha = 1) 
plot(cv.lambda.lasso1)                        

cv.lambda.lasso1                              

# Lasso path
plot(cv.lambda.lasso1$glmnet.fit, 
     "lambda", label=FALSE)


# Extract coefficients at the lambda.min value
coef(cv.lambda.lasso1, s = "lambda.min")

# Cycle for doing 1000 cross validations and take the average of the mean error curves
MSEs <- NULL
for (i in 1:1000){
  cv <- cv.glmnet(X1, Y1, alpha= 1, family = "poisson")
  MSEs <- cbind(MSEs, cv$cvm)
}
rownames(MSEs) <- cv$lambda
lambda.min <- as.numeric(names(which.min(rowMeans(MSEs))))
lambda.min

coef(cv, s = lambda.min) 


