rsq.partial(model2n1d)

#for poisson and gamma
semi_partial_r2_glm <- function(model) {
  if (!inherits(model, "glm"))
    stop("This function currently works for 'glm' objects only.")
  
  mf   <- model.frame(model)
  fam  <- family(model)
  resp <- names(mf)[1]
  
  # all predictors (no intercept)
  terms_full <- attr(terms(model), "term.labels")
  
  # null model
  f_null     <- as.formula(paste(resp, "~ 1"))
  model_null <- glm(f_null, family = fam, data = mf)
  
  LL_null <- as.numeric(logLik(model_null))
  LL_full <- as.numeric(logLik(model))
  
  R2_full <- 1 - (LL_full / LL_null)
  
  out <- data.frame(
    model = deparse(model$call)[1],
    term = terms_full,
    sr2  = NA_real_
  )
  
  for (i in seq_along(terms_full)) {
    terms_reduced <- terms_full[-i]
    
    if (length(terms_reduced) == 0) {
      f_red <- f_null
    } else {
      f_red <- as.formula(paste(resp, "~", paste(terms_reduced, collapse = " + ")))
    }
    
    model_red <- glm(f_red, family = fam, data = mf)
    LL_red    <- as.numeric(logLik(model_red))
    R2_red    <- 1 - (LL_red / LL_null)
    
    out$sr2[i] <- R2_full - R2_red
  }
  
  attr(out, "R2_full") <- R2_full
  out
}

models_SR  <- list(model1p1a, model1p1b, model1p1c, model1p1d)
models_FRic <- list(model3g1a, model3g1b, model3g1c, model3g1d, model3g1e, model3g1f)
models_PD  <- list(model4g1a, model4g1b, model4g1c, model4g1d, model4g1e)
models_PE  <- list(model5g1a, model5g1b)

get_sr2_table <- function(model_list) {
  do.call(rbind, lapply(model_list, semi_partial_r2_glm))
}

sr2_SR   <- get_sr2_table(models_SR)
sr2_FRic <- get_sr2_table(models_FRic)
